import json
import logging.config
import os
import sys
import traceback
from pathlib import Path
from types import TracebackType
from typing import Any, Dict, Iterable, Tuple, Optional, Type, Callable

import click
from geosat.psanp.abstractions.stages import register_plugin_stages
from geosat.tools.awspricetracker import AWSPriceTracker, AWSInstanceIDNotFoundError
from geosat.tools.urlprotocol import UrlProtocols, UrlReader

from psanp.pipeline import Pipeline, override_pipeline_options
from psanp.server.start import start_server
from psanp.standard_stages import register_standard_stages

logger = logging.getLogger(__name__)

LOG_LEVELS = {
    "debug": logging.DEBUG,
    "info": logging.INFO,
    "warning": logging.WARNING,
    "error": logging.ERROR,
    "critical": logging.CRITICAL,
}

OVERRIDE_OPT_HELP = (
    "Option to override parameters contained in the pipeline JSON. "
    "For example: `--override source other_file.las GroundClassifier.gsd 0.125`"
)
USER_OPT_HELP = (
    "Option to specify the name of the user that runs the task command. "
    "Used to link the costs of the task to a project on AWS"
)
LOG_LEVEL_OPT_HELP = f"Level of log displayed (choose from: {list(LOG_LEVELS.keys())})"
LOG_FORMAT_OPT_HELP = "Disable or enable log formatting in JSON"
SERVE_OPT_HELP = (
    "Start a local server that waits for a client to send point clouds to process"
)
HOST_OPT_HELP = (
    "IP to use when hosting the server. Only used if the `--serve` flag is active"
)
PORT_OPT_HELP = (
    "TCP port to use when hosting the server. Only used if the `--serve` flag is active"
)


ExceptHook = Callable[
    [Type[BaseException], BaseException, Optional[TracebackType]], None
]


def _exception_logging_wrap(source_file: Optional[str]) -> ExceptHook:
    if source_file is not None:
        parent_file = os.path.basename("_".join(source_file.split("_")[:-1]))
    else:
        parent_file = None

    def exception_logging(
        exctype: Type[BaseException],
        value: BaseException,
        tracebk: Optional[TracebackType],
    ) -> None:
        """Log exception in one line by using the root logger."""
        logger.exception(
            "".join(traceback.format_exception(exctype, value, tracebk)),
            extra={
                "source_file": source_file,
                "status": "FAILED",
                "status_flag": 0,
                "parent_file": parent_file,
            },
        )

    return exception_logging


def register_all_stages() -> None:
    """Register all the standard and plugin stages that are available in
    the python environment
    """
    register_standard_stages()
    register_plugin_stages()


def run_psanp(pipeline_file: str, override: Dict[str, Any]) -> None:
    """Run psanp from a JSON pipeline file. Elements of the pipeline can be overridden.
    The stages must be registered beforehand. This can be done with:
        - The :func:`register_standard_stages` function
        - The :func:`register_plugin_stages` function
        - The :func:`register_all_stages` function
    """
    with UrlReader(pipeline_file, UrlProtocols()) as stream:
        pipeline_opts = json.load(stream)
    logger.debug("Override options: {}".format(override))
    override_pipeline_options(pipeline_opts, override)
    pipeline = Pipeline.from_options(pipeline_opts)
    pipeline.execute()


@click.command(
    help="A tool to analyze 3D point clouds using pipelines defined as JSON files"
)
@click.argument("pipeline_file", required=False)
@click.option("--override", "-o", nargs=2, multiple=True, help=OVERRIDE_OPT_HELP)
@click.option("--loglevel", "-l", default="info", help=LOG_LEVEL_OPT_HELP)
@click.option(
    "--json-format/--no-json-format",
    "--json_format/--no-json_format",
    "-j/-nj",
    default=True,
    help=LOG_FORMAT_OPT_HELP,
)
@click.option("--username", "-u", default=None, help=USER_OPT_HELP)
@click.option("--serve", "-s", default=False, is_flag=True, help=SERVE_OPT_HELP)
@click.option("--host", "-H", default="0.0.0.0", help=HOST_OPT_HELP)
@click.option("--port", "-P", default=5942, help=PORT_OPT_HELP)
def main(
    pipeline_file: Optional[str] = None,
    override: Iterable[Tuple[str, Any]] = (),
    loglevel: str = "info",
    json_format: bool = False,
    username: Optional[str] = None,
    serve: bool = False,
    host: str = "0.0.0.0",
    port: int = 5942,
) -> None:
    override_dict = dict(override)

    # Logging
    logging.basicConfig(
        level=LOG_LEVELS[loglevel.lower()],
        format="%(asctime)s %(name)s %(levelname)s: %(message)s",
    )
    logging.getLogger("botocore").setLevel(logging.CRITICAL)
    source_file = override_dict.get("source", None)
    if json_format:
        logging_path = Path(Path(__file__).parent, "logging.ini")
        try:
            logging.config.fileConfig(logging_path, disable_existing_loggers=False)
        except KeyError as exception:
            raise FileNotFoundError(logging_path) from exception
        sys.excepthook = _exception_logging_wrap(source_file)

    price_tracker = AWSPriceTracker()
    register_all_stages()
    try:
        if serve:
            start_server(pipeline_file, host, port)
        else:
            if pipeline_file is None:
                raise click.UsageError(
                    "Argument 'PIPELINE_FILE' is required when not in `--serve` mode"
                )
            run_psanp(pipeline_file, override_dict)
    finally:
        try:
            cost = price_tracker.get_job_cost(region_name="us-east-1")
        except AWSInstanceIDNotFoundError as exception:
            logger.warning(f"Impossible to compute the pricing: {exception}")
        else:
            logger.info("pricing", extra={"user": username, "cost": cost})


if __name__ == "__main__":
    main()
